import { Router } from 'express';
import { db } from './db';

export const docRouter = Router();

// Saves the ENTIRE document body. Last PUT wins.
docRouter.put('/docs/:id', async (req, res) => {
  const { html } = req.body;
  await db.query('UPDATE docs SET body=$1, updated_at=now() WHERE id=$2', [html, req.params.id]);
  res.json({ ok: true });
});

docRouter.get('/docs/:id', async (req, res) => {
  const r = await db.query('SELECT body FROM docs WHERE id=$1', [req.params.id]);
  res.json({ html: r.rows[0].body });
});

import { useEffect, useRef, useState } from 'react';

export function Editor({ docId }: { docId: string }) {
  const [html, setHtml] = useState('');
  const timer = useRef<any>();

  useEffect(() => {
    fetch(`/api/docs/${docId}`).then(r => r.json()).then(d => setHtml(d.html));
  }, [docId]);

  function onInput(e: React.FormEvent<HTMLDivElement>) {
    const next = e.currentTarget.innerHTML;
    clearTimeout(timer.current);
    timer.current = setTimeout(() => {
      fetch(`/api/docs/${docId}`, { method: 'PUT', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ html: next }) });
    }, 500);
  }

  return <div contentEditable dangerouslySetInnerHTML={{ __html: html }} onInput={onInput} />;
}

import { WebSocketServer, WebSocket } from 'ws';
import { createClient } from 'redis';
import * as Y from 'yjs';
import { db } from './db';

const pub = createClient(); const sub = createClient();
await pub.connect(); await sub.connect();

const rooms = new Map<string, Set<WebSocket>>();

export function attachRelay(wss: WebSocketServer) {
  wss.on('connection', async (ws, req) => {
    const docId = new URL(req.url!, 'http://x').searchParams.get('doc')!;
    if (!rooms.has(docId)) rooms.set(docId, new Set());
    rooms.get(docId)!.add(ws);
    await sub.subscribe(`doc:${docId}`, (msg) => {
      const buf = Buffer.from(msg, 'base64');
      for (const peer of rooms.get(docId) ?? []) if (peer.readyState === 1) peer.send(buf);
    });
    // send current snapshot as one update
    const snap = await loadSnapshot(docId);
    if (snap) ws.send(snap);
    ws.on('message', async (data: Buffer) => {
      // append-only persist (legal hold) then fan out cross-instance
      await db.query('INSERT INTO doc_updates(doc_id, update_bin, created_at) VALUES($1,$2,now())', [docId, data]);
      await pub.publish(`doc:${docId}`, data.toString('base64'));
    });
    ws.on('close', () => rooms.get(docId)!.delete(ws));
  });
}

async function loadSnapshot(docId: string): Promise<Buffer | null> {
  const r = await db.query('SELECT snapshot_bin FROM doc_snapshots WHERE doc_id=$1 ORDER BY created_at DESC LIMIT 1', [docId]);
  if (!r.rows[0]) return null;
  return r.rows[0].snapshot_bin;
}

import * as Y from 'yjs';
import { db } from './db';

// Runs every 5 min per active doc; folds N small updates into one snapshot.
export async function compact(docId: string) {
  const updates = await db.query('SELECT id, update_bin FROM doc_updates WHERE doc_id=$1 AND compacted=false ORDER BY id', [docId]);
  if (updates.rows.length < 50) return; // keep recent ops hot
  const base = await db.query('SELECT snapshot_bin FROM doc_snapshots WHERE doc_id=$1 ORDER BY created_at DESC LIMIT 1', [docId]);
  const doc = new Y.Doc();
  if (base.rows[0]) Y.applyUpdate(doc, base.rows[0].snapshot_bin);
  for (const u of updates.rows) Y.applyUpdate(doc, u.update_bin);
  const snapshot = Buffer.from(Y.encodeStateAsUpdate(doc));
  await db.query('BEGIN');
  await db.query('INSERT INTO doc_snapshots(doc_id, snapshot_bin, created_at) VALUES($1,$2,now())', [docId, snapshot]);
  await db.query('UPDATE doc_updates SET compacted=true WHERE doc_id=$1 AND id <= $2', [docId, updates.rows.at(-1).id]);
  await db.query('COMMIT');
}

import * as Y from 'yjs';
import { prosemirrorJSONToYDoc } from 'y-prosemirror';
import { htmlToProsemirrorJSON } from './htmlConvert';
import { db } from './db';

// Lazy migration on first open of a doc still in HTML format.
export async function ensureYDoc(docId: string): Promise<void> {
  const r = await db.query('SELECT body, doc_format FROM docs WHERE id=$1 FOR UPDATE', [docId]);
  if (r.rows[0].doc_format === 'yjs') return;
  const pmJson = htmlToProsemirrorJSON(r.rows[0].body);
  const doc = prosemirrorJSONToYDoc(pmJson, 'default');
  const snapshot = Buffer.from(Y.encodeStateAsUpdate(doc));
  await db.query('INSERT INTO doc_snapshots(doc_id, snapshot_bin, created_at) VALUES($1,$2,now())', [docId, snapshot]);
  await db.query("UPDATE docs SET doc_format='yjs' WHERE id=$1", [docId]);
}

import { useEffect, useRef } from 'react';
import * as Y from 'yjs';
import { WebsocketProvider } from 'y-websocket';
import { ySyncPlugin, yCursorPlugin, yUndoPlugin } from 'y-prosemirror';
import { EditorState } from 'prosemirror-state';
import { EditorView } from 'prosemirror-view';
import { schema } from './schema';

export function CollabEditor({ docId, user }: { docId: string; user: { name: string; color: string } }) {
  const host = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const ydoc = new Y.Doc();
    const provider = new WebsocketProvider(WS_URL, docId, ydoc, { params: { doc: docId } });
    provider.awareness.setLocalStateField('user', user);
    const type = ydoc.getXmlFragment('default');
    const state = EditorState.create({ schema, plugins: [ySyncPlugin(type), yCursorPlugin(provider.awareness), yUndoPlugin()] });
    const view = new EditorView(host.current!, { state });
    return () => { view.destroy(); provider.destroy(); ydoc.destroy(); };
  }, [docId]);
  return <div ref={host} />;
}

import { WebSocket } from 'ws';

interface P { userId: string; name: string; x: number; y: number; }
const present = new Map<string, P>(); // key: socket id

export function onConnect(id: string, ws: WebSocket, user: { userId: string; name: string }) {
  present.set(id, { ...user, x: 0, y: 0 });
  ws.on('message', (raw) => {
    const m = JSON.parse(raw.toString());
    if (m.type === 'cursor') {
      const p = present.get(id)!; p.x = m.x; p.y = m.y;
      broadcast({ type: 'cursor', userId: p.userId, x: m.x, y: m.y }); // every move
    }
  });
  ws.on('close', () => { present.delete(id); broadcast({ type: 'leave', socketId: id }); });
}

function broadcast(_m: any) { /* sends to local sockets only */ }

import { Awareness } from 'y-protocols/awareness';

export function wirePresence(awareness: Awareness, user: { userId: string; name: string; color: string }) {
  awareness.setLocalStateField('user', user);
  let pending: { x: number; y: number } | null = null; let raf = 0;
  function flush() { raf = 0; if (pending) { awareness.setLocalStateField('cursor', pending); pending = null; } }
  window.addEventListener('pointermove', (e) => {
    pending = { x: e.clientX, y: e.clientY };
    if (!raf) raf = requestAnimationFrame(flush); // <= one update per frame (~30-60/s capped by rAF)
  });
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'hidden') awareness.setLocalState({ user }); // drop cursor immediately
  });
  window.addEventListener('pagehide', () => awareness.setLocalState(null)); // graceful clear on lid/close
}

import { applyAwarenessUpdate, encodeAwarenessUpdate, Awareness } from 'y-protocols/awareness';
import { createClient } from 'redis';
import * as Y from 'yjs';

const redis = createClient(); await redis.connect();

export function attachPresence(boardId: string, awareness: Awareness, broadcast: (b: Uint8Array) => void) {
  awareness.on('update', async ({ added, updated, removed }: any, _origin: any) => {
    const changed = [...added, ...updated, ...removed];
    broadcast(encodeAwarenessUpdate(awareness, changed));
    for (const clientId of [...added, ...updated]) {
      const st = awareness.getStates().get(clientId);
      if (st?.user) await redis.zAdd(`pres:${boardId}`, { score: Date.now(), value: st.user.userId });
    }
  });
}

// Single elected sweeper per board
export async function sweep(boardId: string, awareness: Awareness) {
  const cutoff = Date.now() - 5000;
  const stale = await redis.zRangeByScore(`pres:${boardId}`, 0, cutoff);
  if (stale.length) {
    await redis.zRemRangeByScore(`pres:${boardId}`, 0, cutoff);
    // remove awareness states whose user is stale
    for (const [cid, st] of awareness.getStates()) if (stale.includes((st as any)?.user?.userId)) awareness.getStates().delete(cid);
  }
}

import { useSyncExternalStore } from 'react';
import { Awareness } from 'y-protocols/awareness';

export function AvatarStack({ awareness }: { awareness: Awareness }) {
  const states = useSyncExternalStore(
    (cb) => { awareness.on('change', cb); return () => awareness.off('change', cb); },
    () => awareness.getStates()
  );
  const byUser = new Map<string, any>();
  for (const st of states.values()) if (st.user) byUser.set(st.user.userId, st.user); // dedupe multi-tab
  return <div className="avatars">{[...byUser.values()].map(u => <span key={u.userId} style={{ background: u.color }}>{u.name[0]}</span>)}</div>;
}

import merge from 'lodash.merge';

// Called on reconnect with the locally edited doc and the server doc.
export function resolve(localDoc: any, serverDoc: any) {
  // lodash merge: arrays merged by index, objects deep-merged, scalars = source wins
  const merged = merge({}, serverDoc, localDoc);
  return merged;
}

export async function syncOnReconnect(jobId: string, localDoc: any) {
  const server = await api.get(`/jobs/${jobId}`);
  const { resolve } = await import('./merge');
  const merged = resolve(localDoc, server.data);
  await api.put(`/jobs/${jobId}`, merged); // pushes whole doc back
  return merged;
}

import * as Automerge from '@automerge/automerge';

export type Job = { status: string; checklist: { id: string; label: string; done: boolean }[]; notes: string };

export function fromLegacyJson(json: Job): Automerge.Doc<Job> {
  return Automerge.from<Job>(json);
}

export function setStatus(doc: Automerge.Doc<Job>, status: string, by: string) {
  return Automerge.change(doc, `status by ${by}`, (d) => { d.status = status; });
}

export function toggleItem(doc: Automerge.Doc<Job>, id: string, by: string) {
  return Automerge.change(doc, `toggle ${id} by ${by}`, (d) => {
    const it = d.checklist.find(c => c.id === id); if (it) it.done = !it.done;
  });
}

export function addItem(doc: Automerge.Doc<Job>, item: { id: string; label: string }, by: string) {
  return Automerge.change(doc, `add ${item.id} by ${by}`, (d) => { d.checklist.push({ ...item, done: false }); });
}

import * as Automerge from '@automerge/automerge';

export async function syncOnReconnect(jobId: string, local: Automerge.Doc<any>, api: any) {
  const localHeads = Automerge.getHeads(local);
  // Ask server only for changes we don't have, send only changes it doesn't have.
  const { serverChanges, serverHeads } = await api.post(`/jobs/${jobId}/sync`, { heads: localHeads });
  let merged = local;
  for (const ch of serverChanges) [merged] = Automerge.applyChanges(merged, [new Uint8Array(ch)]);
  const toSend = Automerge.getChanges(Automerge.view(merged, serverHeads), merged);
  if (toSend.length) await api.post(`/jobs/${jobId}/push`, { changes: toSend.map(c => Array.from(c)) });
  return merged;
}

import { Router } from 'express';
import * as Automerge from '@automerge/automerge';
import { db } from './db';

export const sync = Router();

async function load(jobId: string) {
  const r = await db.query('SELECT changes FROM job_doc WHERE id=$1', [jobId]);
  let doc = Automerge.init();
  for (const c of r.rows[0].changes) [doc] = Automerge.applyChanges(doc, [new Uint8Array(c)]);
  return doc;
}

sync.post('/jobs/:id/sync', async (req, res) => {
  const doc = await load(req.params.id);
  const clientHeads = req.body.heads as string[];
  const missing = Automerge.getChanges(Automerge.view(doc, clientHeads), doc).map(c => Array.from(c));
  res.json({ serverChanges: missing, serverHeads: Automerge.getHeads(doc) });
});

sync.post('/jobs/:id/push', async (req, res) => {
  let doc = await load(req.params.id);
  const before = JSON.stringify((doc as any).status);
  for (const c of req.body.changes) [doc] = Automerge.applyChanges(doc, [new Uint8Array(c)]);
  // capture conflicts for audit
  const conflicts = (Automerge.getConflicts(doc as any, 'status') || null);
  await db.query('UPDATE job_doc SET changes=$1 WHERE id=$2', [Automerge.getAllChanges(doc).map(c => Array.from(c)), req.params.id]);
  if (conflicts) await db.query('INSERT INTO sync_conflicts(job_id, field, detail, created_at) VALUES($1,$2,$3,now())', [req.params.id, 'status', JSON.stringify(conflicts)]);
  res.json({ ok: true, heads: Automerge.getHeads(doc) });
});

import { Router } from 'express';
import { db } from '../db';
export const cards = Router();

cards.patch('/cards/:id/move', async (req, res) => {
  const { columnId, position } = req.body;
  // shifts everything below to make room — O(n) and racy
  await db.query('UPDATE cards SET position = position + 1 WHERE column_id=$1 AND position >= $2', [columnId, position]);
  await db.query('UPDATE cards SET column_id=$1, position=$2 WHERE id=$3', [columnId, position, req.params.id]);
  res.json({ ok: true });
});

export function onDrop(cardId: string, toCol: string, idx: number) {
  // optimistic local insert, then PATCH; on conflict the source copy is never reconciled
  store.insert(toCol, cardId, idx);
  fetch(`/api/cards/${cardId}/move`, { method: 'PATCH', body: JSON.stringify({ columnId: toCol, position: idx }) });
}

import * as Y from 'yjs';
import { generateKeyBetween } from 'fractional-indexing';

export function moveCard(ydoc: Y.Doc, cardId: string, fromCol: string, toCol: string, beforeId: string | null, afterId: string | null) {
  const cols = ydoc.getMap('columns');
  const order = ydoc.getMap('order'); // cardId -> fractional key
  ydoc.transact(() => {
    const src = cols.get(fromCol) as Y.Array<string>;
    const idx = src.toArray().indexOf(cardId);
    if (idx >= 0) src.delete(idx, 1); // atomic remove from source
    const dst = cols.get(toCol) as Y.Array<string>;
    const beforeKey = beforeId ? (order.get(beforeId) as string) : null;
    const afterKey = afterId ? (order.get(afterId) as string) : null;
    order.set(cardId, generateKeyBetween(beforeKey, afterKey));
    // insert keeping array sorted by fractional key
    const arr = dst.toArray();
    let insertAt = arr.findIndex(id => (order.get(id) as string) > (order.get(cardId) as string));
    if (insertAt < 0) insertAt = arr.length;
    dst.insert(insertAt, [cardId]);
  });
}

import * as Y from 'yjs';
import { db } from '../db';

// Debounced: materialize Y.Doc board state back into the relational cards table.
export async function project(boardId: string, ydoc: Y.Doc) {
  const cols = ydoc.getMap('columns');
  const order = ydoc.getMap('order');
  await db.query('BEGIN');
  for (const [colId, arr] of cols.entries()) {
    const ids = (arr as Y.Array<string>).toArray();
    for (const cardId of ids) {
      await db.query('UPDATE cards SET column_id=$1, frac_key=$2 WHERE id=$3', [colId, order.get(cardId), cardId]);
    }
  }
  await db.query('COMMIT');
}

import { generateNKeysBetween } from 'fractional-indexing';
import { db } from '../db';

export async function migrateBoard(boardId: string) {
  const r = await db.query('SELECT id, column_id FROM cards WHERE board_id=$1 ORDER BY column_id, position', [boardId]);
  const byCol: Record<string, string[]> = {};
  for (const row of r.rows) (byCol[row.column_id] ??= []).push(row.id);
  await db.query('BEGIN');
  for (const [, ids] of Object.entries(byCol)) {
    const keys = generateNKeysBetween(null, null, ids.length);
    for (let i = 0; i < ids.length; i++) await db.query('UPDATE cards SET frac_key=$1 WHERE id=$2', [keys[i], ids[i]]);
  }
  await db.query('COMMIT');
}

export function onEdit(sheet: Sheet, addr: string, value: string) {
  sheet.cells[addr] = { value };
  // broadcast the ENTIRE sheet — O(cells) per keystroke
  ws.send(JSON.stringify({ type: 'sheet', cells: sheet.cells }));
}

export function onRemote(msg: any) {
  sheet.cells = msg.cells; // wholesale replace, drops any in-flight local edit
  recalc(sheet);
}

export function insertRow(sheet: Sheet, at: number) {
  // shifts cell addresses but does NOT update formulas that reference them
  shiftCellsDown(sheet, at);
}

export type CellOp =
  | { kind: 'set'; addr: string; value: string; vv: Record<string, number> }
  | { kind: 'insertRow'; at: number; vv: Record<string, number> }
  | { kind: 'deleteCol'; at: number; vv: Record<string, number> };

export type SeqOp = CellOp & { seq: number; actor: string };

import { CellOp } from './op-types';
import { rewriteFormula, shiftAddr } from './refs';

// Transform a pending local op against an already-applied remote op.
export function transform(local: CellOp, applied: CellOp): CellOp {
  if (applied.kind === 'insertRow') {
    if (local.kind === 'set') {
      return { ...local, addr: shiftAddr(local.addr, 'row', applied.at, +1), value: rewriteFormula(local.value, 'row', applied.at, +1) };
    }
  }
  if (applied.kind === 'deleteCol') {
    if (local.kind === 'set') {
      return { ...local, addr: shiftAddr(local.addr, 'col', applied.at, -1), value: rewriteFormula(local.value, 'col', applied.at, -1) };
    }
  }
  return local;
}

import { db } from '../db';
import { SeqOp, CellOp } from '../sheet/op-types';

const seqBySheet = new Map<string, number>();

export async function submit(sheetId: string, op: CellOp, actor: string, broadcast: (o: SeqOp) => void) {
  const seq = (seqBySheet.get(sheetId) ?? 0) + 1;
  seqBySheet.set(sheetId, seq);
  const seqOp: SeqOp = { ...op, seq, actor } as SeqOp;
  await db.query('INSERT INTO sheet_ops(sheet_id, seq, actor, op, created_at) VALUES($1,$2,$3,$4,now())', [sheetId, seq, actor, JSON.stringify(op)]);
  broadcast(seqOp); // linearized, total order per sheet
  return seq;
}

import { CellOp, SeqOp } from './op-types';
import { transform } from './transform';
import { recalc } from './recalc';

export class SheetClient {
  pending: CellOp[] = [];
  applied = 0;
  constructor(public sheet: any) {}
  localEdit(op: CellOp) { this.pending.push(op); this.apply(op); /* optimistic */ }
  onRemote(s: SeqOp) {
    // transform our pending ops against the authoritative op, then apply it
    this.pending = this.pending.map(p => transform(p, s));
    this.apply(s);
    this.applied = s.seq;
    recalc(this.sheet); // deterministic once converged
  }
  private apply(op: CellOp) { /* mutate sheet model for set/insert/delete */ }
}

import { applyPatch, createPatch } from 'diff';

let lastSent = '';
export function onChange(text: string) {
  const patch = createPatch('f', lastSent, text);
  ws.send(JSON.stringify({ type: 'patch', patch }));
  lastSent = text;
}

export function onRemote(msg: any, editor: any) {
  const cur = editor.getValue();
  const next = applyPatch(cur, msg.patch);
  if (next === false) return; // patch failed on overlap -> silent divergence
  editor.setValue(next); // resets cursor/selection
}

export function showCursor(line: number, col: number) {
  // absolute line/col — wrong after any remote insertion above
  decorate(line, col);
}

import * as Y from 'yjs';
import { MonacoBinding } from 'y-monaco';
import { WebsocketProvider } from 'y-websocket';
import type { editor } from 'monaco-editor';

export function bindCollab(model: editor.ITextModel, ed: editor.IStandaloneCodeEditor, fileId: string, user: { name: string; color: string }) {
  const ydoc = new Y.Doc();
  const provider = new WebsocketProvider(WS_URL, fileId, ydoc);
  provider.awareness.setLocalStateField('user', user);
  const yText = ydoc.getText('content');
  const binding = new MonacoBinding(yText, model, new Set([ed]), provider.awareness);
  const undo = new Y.UndoManager(yText, { trackedOrigins: new Set([binding]) }); // per-user undo
  ed.addCommand(/* Ctrl+Z */ 2078, () => undo.undo());
  ed.addCommand(/* Ctrl+Shift+Z */ 2078 | 1024, () => undo.redo());
  return { ydoc, provider, yText, undo, destroy: () => { binding.destroy(); provider.destroy(); ydoc.destroy(); } };
}

import * as Y from 'yjs';
import type { editor } from 'monaco-editor';

// Anchor LSP diagnostic ranges to Yjs relative positions so they survive remote edits.
export function anchorDiagnostics(yText: Y.Text, model: editor.ITextModel, diags: { start: number; end: number; message: string }[]) {
  return diags.map(d => ({
    relStart: Y.createRelativePositionFromTypeIndex(yText, d.start),
    relEnd: Y.createRelativePositionFromTypeIndex(yText, d.end),
    message: d.message,
  }));
}

export function resolveDiagnostics(doc: Y.Doc, anchored: any[]) {
  return anchored.map(a => {
    const s = Y.createAbsolutePositionFromRelativePosition(a.relStart, doc);
    const e = Y.createAbsolutePositionFromRelativePosition(a.relEnd, doc);
    return s && e ? { start: s.index, end: e.index, message: a.message } : null;
  }).filter(Boolean);
}

import { setupWSConnection } from 'y-websocket/bin/utils';
import { db } from '../db';
import * as Y from 'yjs';

// Persistence hooks: load snapshot on first client, debounce-save on update.
export function fileRoom(ws: any, req: any) {
  setupWSConnection(ws, req, {
    docName: new URL(req.url, 'http://x').pathname.slice(1),
    gc: true,
  });
}

export async function persist(fileId: string, ydoc: Y.Doc) {
  const update = Buffer.from(Y.encodeStateAsUpdate(ydoc));
  await db.query('INSERT INTO file_state(file_id, state_bin, updated_at) VALUES($1,$2,now()) ON CONFLICT(file_id) DO UPDATE SET state_bin=$2, updated_at=now()', [fileId, update]);
}

import { Router } from 'express';
import { db } from '../db';
export const react = Router();
react.post('/posts/:id/react', async (req, res) => {
  const { emoji } = req.body;
  const r = await db.query('SELECT count FROM reactions WHERE post_id=$1 AND emoji=$2', [req.params.id, emoji]);
  const next = (r.rows[0]?.count ?? 0) + 1; // read-modify-write race
  await db.query('INSERT INTO reactions(post_id,emoji,count) VALUES($1,$2,$3) ON CONFLICT(post_id,emoji) DO UPDATE SET count=$3', [req.params.id, emoji, next]);
  io.to(req.params.id).emit('reaction', { emoji, count: next });
  res.json({ count: next });
});

import * as Y from 'yjs';
export function toggle(ydoc: Y.Doc, emoji: string, userId: string) {
  const reactions = ydoc.getMap('reactions');
  let set = reactions.get(emoji) as Y.Map<boolean>;
  if (!set) { set = new Y.Map(); reactions.set(emoji, set); }
  if (set.has(userId)) set.delete(userId); else set.set(userId, true);
}
export function count(ydoc: Y.Doc, emoji: string): number {
  const set = ydoc.getMap('reactions').get(emoji) as Y.Map<boolean> | undefined;
  return set ? set.size : 0; // derived, never a racy integer
}

import * as Y from 'yjs';
import { db } from '../db';
export async function project(postId: string, ydoc: Y.Doc) {
  const reactions = ydoc.getMap('reactions');
  for (const [emoji, set] of reactions.entries()) {
    await db.query('INSERT INTO reactions(post_id,emoji,count) VALUES($1,$2,$3) ON CONFLICT(post_id,emoji) DO UPDATE SET count=$3', [postId, emoji, (set as Y.Map<boolean>).size]);
  }
}

import { createClient } from 'redis';
import * as Y from 'yjs';
