import * as Y from 'yjs';
export function fields(ydoc: Y.Doc){ return ydoc.getArray('fields') as Y.Array<Y.Map<any>>; }
export function addField(ydoc: Y.Doc, at:number, spec:{key:string;type:string}){
  const m=new Y.Map(); m.set('key',spec.key); m.set('type',spec.type); m.set('rules', new Y.Map());
  fields(ydoc).insert(at,[m]);
}
