import * as Y from 'yjs';
export function toJsonSchema(ydoc: Y.Doc){
  const props:Record<string,any>={};
  for(const f of (ydoc.getArray('fields') as Y.Array<Y.Map<any>>)){
    const rules=(f.get('rules') as Y.Map<any>).toJSON();
    props[f.get('key')]={ type: f.get('type'), ...rules };
  }
  return { type:'object', properties: props };
}

import * as Y from 'yjs';
