export async function importForm(formId:string){
  const r=await db.query('SELECT fields FROM forms WHERE id=$1',[formId]);
  const ydoc=new Y.Doc(); const arr=ydoc.getArray('fields');
  for(const f of r.rows[0].fields){ const m=new Y.Map(); m.set('key',f.key); m.set('type',f.type); const rl=new Y.Map(); for(const[k,v]of Object.entries(f.rules||{}))rl.set(k,v); m.set('rules',rl); arr.push([m]); }
  return Buffer.from(Y.encodeStateAsUpdate(ydoc));
}

