import { WebSocketServer } from 'ws';
import jwt from 'jsonwebtoken';
import { canAccessPlan } from './authz';
const wss=new WebSocketServer({ noServer:true });
server.on('upgrade', async (req,sock,head)=>{
  try{
    const url=new URL(req.url,'http://x');
    const token=url.searchParams.get('token')||'';
    const claims:any=jwt.verify(token, PUBLIC_KEY,{ algorithms:['RS256'] });
    const planId=url.searchParams.get('room')||'';
    const grant=await canAccessPlan(claims.sub, planId); // {read:boolean, write:boolean}
    if(!grant.read){ sock.write('HTTP/1.1 403 Forbidden\r\n\r\n'); sock.destroy(); return; }
    wss.handleUpgrade(req,sock,head,ws=>{ (ws as any).ctx={ user:claims.sub, planId, write:grant.write, exp:claims.exp }; onConn(ws); });
  }catch{ sock.write('HTTP/1.1 401 Unauthorized\r\n\r\n'); sock.destroy(); }
});

import { setupWSConnection } from 'y-websocket/bin/utils';
const MSG_SYNC=0, MSG_AWARENESS=1;
export function onConn(ws:any){
  const orig=ws.on.bind(ws);
  setupWSConnection(ws, ws.req, { docName: ws.ctx.planId });
  ws.prependListener('message',(data:Buffer)=>{
    const type=data[0];
    // read-only sockets may send awareness (cursors) but not sync updates
    if(!ws.ctx.write && type===MSG_SYNC && data[1]===2 /*sync step2/update*/){ ws.removeAllListeners('message'); ws.close(4003,'read-only'); }
  });
}

