export function renderAll(doc:Y.Doc, awareness:Awareness, draw:(s:{anchor:number;head:number;color:string;name:string})=>void){
  for(const[clientId,st]of awareness.getStates()){
    if(clientId===awareness.clientID || !st.cursor || !st.user) continue;
    const sel=resolveSelection(doc, st); if(!sel) continue;
    draw({ ...sel, color: colorFor(st.user.userId), name: st.user.name });
  }
}

import { Awareness, encodeAwarenessUpdate } from 'y-protocols/awareness';
export function relay(awareness:Awareness, peers:Set<any>){
  awareness.on('update',({added,updated,removed}:any)=>{
    const changed=[...added,...updated,...removed];
    const enc=encodeAwarenessUpdate(awareness,changed);
    for(const p of peers) p.send(enc); // immediate O(N) per change
  });
}

import { Awareness, encodeAwarenessUpdate } from 'y-protocols/awareness';
export class Coalescer{
  private dirty=new Set<number>();
  constructor(private awareness:Awareness, private peers:Set<any>){
    awareness.on('update',({added,updated,removed}:any)=>{ for(const id of [...added,...updated,...removed]) this.dirty.add(id); });
    setInterval(()=>this.flush(),100);
  }
  private flush(){
    if(this.dirty.size===0) return;
    const enc=encodeAwarenessUpdate(this.awareness,[...this.dirty]); // one merged frame per tick
    for(const p of this.peers) p.send(enc);
    this.dirty.clear();
  }
}

export class ReactionLane{
  private queue:any[]=[];
  constructor(private peers:Set<any>){ setInterval(()=>this.flush(),100); }
  push(r:any){ this.queue.push(r); } // never sampled away
  private flush(){ if(!this.queue.length) return; const batch=this.queue.splice(0); for(const p of this.peers) p.send(JSON.stringify({type:'reactions',batch})); }
}

const buckets=new Map<string,{tokens:number;ts:number}>();
export function allow(userId:string, isPresenter:boolean){
  const cap=isPresenter?30:10; const now=Date.now();
  let b=buckets.get(userId); if(!b){ b={tokens:cap,ts:now}; buckets.set(userId,b); }
  const refill=((now-b.ts)/1000)*cap; b.tokens=Math.min(cap,b.tokens+refill); b.ts=now;
  if(b.tokens<1) return false; b.tokens-=1; return true;
}

