import * as Y from 'yjs';
export function claimCharacter(ydoc:Y.Doc, player:string, charId:string){
  const claims=ydoc.getMap('charClaims'); // charId -> playerId
  ydoc.transact(()=>{
    const cur=claims.get(charId) as string|undefined;
    if(cur && cur!==player){ /* deterministic tie-break: lower id keeps it */ if(player < cur) claims.set(charId,player); }
    else claims.set(charId,player);
    // release any other char this player held
    for(const[c,p]of claims.entries()) if(p===player && c!==charId) claims.delete(c);
  });
}
export function resolvePicks(ydoc:Y.Doc){ const m=ydoc.getMap('charClaims'); return Object.fromEntries([...m.entries()]); }

import * as Y from 'yjs';
export class TickBroadcaster{
  private pending:Uint8Array[]=[];
  constructor(doc:Y.Doc, private send:(u:Uint8Array)=>void){ doc.on('update',u=>this.pending.push(u)); this.loop(); }
  private loop(){ setInterval(()=>{ if(!this.pending.length)return; const merged=Y.mergeUpdates(this.pending); this.pending=[]; this.send(merged); }, 1000/60); }
}

import * as Y from 'yjs';
import { resolvePicks } from './exclusivePick';
export function autoRebind(ydoc:Y.Doc, player:string, freeChars:string[]){
  const picks=resolvePicks(ydoc);
  if(Object.values(picks).filter(p=>p===player).length===0 && freeChars[0]){
    ydoc.getMap('charClaims').set(freeChars[0], player); // loser gets next free slot
  }
}

