export function setSetpoint(doc:Automerge.Doc<Cfg>, v:number, origin:'operator'|'gateway'){
  return Automerge.change(doc,`setpoint=${v} by ${origin}`,d=>{ d.setpoint=v; d._origin.setpoint=origin; });
}

import * as Automerge from '@automerge/automerge';
export function resolve(doc:any){
  const conf=Automerge.getConflicts(doc,'setpoint');
  if(!conf || Object.keys(conf).length<=1) return doc;
  // operator intent beats gateway automation on conflict
  const entries=Object.entries(conf);
  const operatorVal=entries.find(([,v])=> doc._origin?.setpoint==='operator');
  const chosen=operatorVal? operatorVal[1] : entries.sort()[0][1];
  return Automerge.change(doc,'resolve setpoint (operator-priority)',d=>{ d.setpoint=chosen as number; });
}

import * as Automerge from '@automerge/automerge';
export async function syncWithServer(local:any, transport:any){
  const heads=Automerge.getHeads(local);
  const { changes, serverHeads }=await transport.send({ heads }); // server returns only missing changes
  let merged=local; for(const c of changes)[merged]=Automerge.applyChanges(merged,[new Uint8Array(c)]);
  const toSend=Automerge.getChanges(Automerge.view(merged,serverHeads),merged);
  if(toSend.length) await transport.push(toSend.map(c=>Array.from(c)));
  return merged;
}

