import * as Y from 'yjs';
const MAX_NODES=50000, MAX_BYTES=8*1024*1024;
export function validateAndApply(live:Y.Doc, update:Uint8Array):{ ok:boolean; reason?:string }{
  let clone:Y.Doc;
  try{ clone=new Y.Doc(); Y.applyUpdate(clone, Y.encodeStateAsUpdate(live)); Y.applyUpdate(clone, update); }
  catch{ return { ok:false, reason:'malformed' }; }
  const size=Y.encodeStateAsUpdate(clone).byteLength; if(size>MAX_BYTES) return { ok:false, reason:'too_large' };
  if(countNodes(clone)>MAX_NODES) return { ok:false, reason:'too_many_nodes' };
  Y.applyUpdate(live, update); // commit only after passing on the clone
  return { ok:true };
}
function countNodes(doc:Y.Doc){ let n=0; doc.share.forEach(t=>{ n+=(t as any)._map?.size||0; }); return n; }

import * as Y from 'yjs';
import DOMPurify from 'isomorphic-dompurify';
export function sanitizeDoc(doc:Y.Doc){
  for(const[,t]of doc.share){
    if(t instanceof Y.Text){ const raw=t.toString(); const clean=DOMPurify.sanitize(raw,{ ALLOWED_TAGS:[] }); if(clean!==raw){ t.delete(0,t.length); t.insert(0,clean); } }
  }
}

