const storage=new MMKV();
export function attachOffline(doc:Y.Doc, noteId:string){
  const key='ydoc:'+noteId;
  const saved=storage.getString(key);
  if(saved) Y.applyUpdate(doc, Uint8Array.from(atob(saved),c=>c.charCodeAt(0)));
  doc.on('update',()=>{ const bin=Y.encodeStateAsUpdate(doc); storage.set(key, btoa(String.fromCharCode(...bin))); });
}

