export function attachSync(doc:Y.Doc, noteId:string){
  let provider:WebsocketProvider|null=null;
  NetInfo.addEventListener(state=>{
    if(state.isConnected && !provider){ provider=new WebsocketProvider(WS_URL, noteId, doc); }
    if(!state.isConnected && provider){ provider.disconnect(); provider.destroy(); provider=null; }
  });
}

import { useEffect, useRef, useState } from 'react';
import { TextInput } from 'react-native';
import * as Y from 'yjs';
import { attachOffline } from './yPersistence';
import { attachSync } from './connectivitySync';
export function NoteEditor({ noteId }:{ noteId:string }){
  const [text,setText]=useState('');
  const yText=useRef<Y.Text>();
  useEffect(()=>{ const doc=new Y.Doc(); attachOffline(doc,noteId); attachSync(doc,noteId);
    const t=doc.getText('content'); yText.current=t; setText(t.toString());
    const obs=()=>setText(t.toString()); t.observe(obs);
    return ()=>{ t.unobserve(obs); doc.destroy(); };
  },[noteId]);
  return <TextInput multiline value={text} onChangeText={v=>{ const t=yText.current!; t.delete(0,t.length); t.insert(0,v); }} />;
}

import { Awareness } from 'y-protocols/awareness';
export function wireTyping(awareness:Awareness, agent:{ id:string; name:string }){
  let idle:any;
  function setTyping(){ awareness.setLocalStateField('typing',{ agentId:agent.id, name:agent.name, at:Date.now() }); clearTimeout(idle); idle=setTimeout(()=>awareness.setLocalStateField('typing', null),1000); }
