import * as Y from 'yjs';
export const LOCAL={};
export class OptimisticEditor{
  pending=new Map<string,{ stackItem:any }>();
  constructor(public ydoc:Y.Doc, public undo:Y.UndoManager){}
  setAmount(cat:string, amount:number){
    const opId=crypto.randomUUID();
    this.ydoc.transact(()=>{ this.ydoc.getMap('amounts').set(cat,amount); this.ydoc.getMap('amounts').set('_op',opId); }, LOCAL);
    this.pending.set(opId,{ stackItem:this.undo.undoStack.at(-1) });
    provider.send({ type:'op', opId });
    return opId;
  }
  onReject(opId:string, reason:string){
    const p=this.pending.get(opId); if(!p) return;
    this.undo.undo(); // compensate exactly this op
    this.pending.delete(opId);
    toast(`Edit rejected: ${reason}`);
  }
  onAccept(opId:string){ this.pending.delete(opId); }
}

import * as Y from 'yjs';
export function validate(doc:Y.Doc, update:Uint8Array, opId:string, cap:number, reply:(m:any)=>void, broadcast:(u:Uint8Array)=>void){
  const clone=new Y.Doc(); Y.applyUpdate(clone, Y.encodeStateAsUpdate(doc)); Y.applyUpdate(clone, update);
  const total=[...(clone.getMap('amounts').entries())].filter(([k])=>k!=='_op').reduce((s,[,v])=>s+(v as number),0);
  if(total>cap){ reply({ type:'reject', opId, reason:`exceeds cap ${cap}` }); return; }
  Y.applyUpdate(doc, update); reply({ type:'ack', opId }); broadcast(update);
}

export function wire(provider:any, editor:any){
