export function selectTop(states:Map<number,any>, presenterId:string, viewportCenter:{x:number;y:number}, limit=8){
  const all=[...states.values()].filter(s=>s.cursor);
  const presenter=all.find(s=>s.user.id===presenterId);
  const rest=all.filter(s=>s.user.id!==presenterId)
    .sort((a,b)=> (Date.now()-b.cursor.at)-(Date.now()-a.cursor.at) || dist(a.cursor,viewportCenter)-dist(b.cursor,viewportCenter));
  const top=[...(presenter?[presenter]:[]), ...rest].slice(0,limit);
  return { top, othersCount: Math.max(0, all.length-top.length) };
}
