import * as Y from 'yjs';
import { generateKeyBetween } from 'fractional-indexing';
export function moveNode(ydoc:Y.Doc, id:string, fromParent:string, toParent:string, before:string|null, after:string|null){
  if(isDescendant(ydoc, toParent, id)) throw new Error('cycle');
  ydoc.transact(()=>{
    const nodes=ydoc.getMap('nodes');
    const fromArr=(nodes.get(fromParent) as Y.Map<any>).get('children') as Y.Array<string>;
    const i=fromArr.toArray().indexOf(id); if(i>=0) fromArr.delete(i,1);
    const order=ydoc.getMap('order'); order.set(id, generateKeyBetween(before?order.get(before) as string:null, after?order.get(after) as string:null));
    const toArr=(nodes.get(toParent) as Y.Map<any>).get('children') as Y.Array<string>;
    const arr=toArr.toArray(); let at=arr.findIndex(c=>(order.get(c) as string)>(order.get(id) as string)); if(at<0) at=arr.length; toArr.insert(at,[id]);
  });
}
export function isDescendant(ydoc:Y.Doc, candidate:string, ancestor:string):boolean{
  const nodes=ydoc.getMap('nodes'); let cur=candidate;
  const parentOf=(n:string)=>{ for(const[pid,m]of nodes.entries()) if(((m as Y.Map<any>).get('children') as Y.Array<string>).toArray().includes(n)) return pid; return null; };
  while(cur){ if(cur===ancestor) return true; cur=parentOf(cur) as string; } return false;
}

