import * as Y from 'yjs';
import { generateNKeysBetween } from 'fractional-indexing';
export function importFlat(rows:{ id:string; parent_id:string|null; order:number; text:string }[]){
  const ydoc=new Y.Doc(); const nodes=ydoc.getMap('nodes'); const order=ydoc.getMap('order');
  for(const r of rows){ const m=new Y.Map(); m.set('text',r.text); m.set('children', new Y.Array()); nodes.set(r.id, m); }
  const byParent:Record<string,string[]>={}; for(const r of rows){ const p=r.parent_id??'root'; (byParent[p]??=[]).push(r.id); }
  for(const[p,ids]of Object.entries(byParent)){ ids.sort(); const keys=generateNKeysBetween(null,null,ids.length); ids.forEach((id,i)=>{ order.set(id,keys[i]); if(nodes.get(p)) ((nodes.get(p) as Y.Map<any>).get('children') as Y.Array<string>).push([id]); }); }
  return ydoc;
}

