export function onReconnect(doc:Y.Doc, ws:WebSocket){
  const enc=encoding.createEncoder(); encoding.writeVarUint(enc,0/*sync*/); encoding.writeVarUint(enc,0/*step1*/);
  encoding.writeVarUint8Array(enc, Y.encodeStateVector(doc)); // send what we HAVE
  ws.send(encoding.toUint8Array(enc));
}
export function onStep1(doc:Y.Doc, sv:Uint8Array, reply:(b:Uint8Array)=>void){
  const enc=encoding.createEncoder(); encoding.writeVarUint(enc,0); encoding.writeVarUint(enc,1/*step2*/);
  encoding.writeVarUint8Array(enc, Y.encodeStateAsUpdate(doc, sv)); // only the diff they're missing
