}

import * as Y from 'yjs';
export class BatchedApplier{
  private dirty=false;
  constructor(private doc:Y.Doc, private render:()=>void){}
  apply(update:Uint8Array){ Y.applyUpdate(this.doc, update); this.dirty=true; /* applyUpdate is idempotent for seen structs */ }
  flush(){ if(this.dirty){ this.render(); this.dirty=false; } } // one render after catch-up
}

import * as Y from 'yjs';
import { decoding } from 'lib0';
import { onStep1 } from './properSync';
import { BatchedApplier } from './applyBatched';
export function wire(doc:Y.Doc, ws:WebSocket, render:()=>void){
  const applier=new BatchedApplier(doc, render);
  ws.onmessage=(ev)=>{ const dec=decoding.createDecoder(new Uint8Array(ev.data)); const msg=decoding.readVarUint(dec); if(msg===0){ const step=decoding.readVarUint(dec); if(step===0){ onStep1(doc, decoding.readVarUint8Array(dec), b=>ws.send(b)); } else { applier.apply(decoding.readVarUint8Array(dec)); } } };
  setInterval(()=>applier.flush(), 16); // batch renders to a frame
}

