}

import * as Y from 'yjs';
const POLICY:Record<string,string[]>={ viewer:['comments'], editor:['comments','body'], legal:['comments','body','lock'] };
export function changedSubtrees(live:Y.Doc, update:Uint8Array):Set<string>{
  const before=new Map<string,number>(); live.share.forEach((t,k)=>before.set(k,(t as any)._item?.id?.clock??0));
  const clone=new Y.Doc(); Y.applyUpdate(clone, Y.encodeStateAsUpdate(live)); Y.applyUpdate(clone, update);
  const changed=new Set<string>();
  clone.share.forEach((t,k)=>{ const c=(t as any)._item?.id?.clock??0; if(c!==(before.get(k)??-1)) changed.add(k); });
  // also detect deep changes by comparing encoded subtree hashes
  return changed;
}
export function authorize(role:string, changed:Set<string>):{ ok:boolean; reason?:string }{
  const allowed=new Set(POLICY[role]||[]);
  for(const k of changed) if(!allowed.has(k)) return { ok:false, reason:`role ${role} cannot edit ${k}` };
  return { ok:true };
}

import * as Y from 'yjs';
import { changedSubtrees, authorize } from './subtreeAuthz';
import { roleOf } from './perms';
export async function onUpdate(doc:Y.Doc, update:Uint8Array, userId:string, contractId:string, reply:(m:any)=>void, broadcast:(u:Uint8Array)=>void){
  const role=await roleOf(userId, contractId);
  const changed=changedSubtrees(doc, update);
  const verdict=authorize(role, changed);
  if(!verdict.ok){ reply({ type:'reject', reason: verdict.reason }); return; }
  Y.applyUpdate(doc, update); broadcast(update);
}

