export async function pasteImage(ydoc:Y.Doc, blob:Blob, x:number, y:number, w:number, h:number){
  const buf=new Uint8Array(await blob.arrayBuffer());
  const hash=await sha256Hex(buf); // content address -> dedupe
  const exists=await api.head(`/assets/${hash}`).then(()=>true).catch(()=>false);
  if(!exists) await api.put(`/assets/${hash}`, buf, { headers:{ 'content-type': blob.type } });
  ydoc.getMap('items').set(crypto.randomUUID(), { type:'image', assetId: hash, x, y, w, h }); // tiny ref only
}
async function sha256Hex(buf:Uint8Array){ const d=await crypto.subtle.digest('SHA-256', buf); return [...new Uint8Array(d)].map(b=>b.toString(16).padStart(2,'0')).join(''); }

