export function LazyImage({ assetId, w, h }:{ assetId:string; w:number; h:number }){
  const ref=useRef<HTMLDivElement>(null); const [src,setSrc]=useState<string>();
  useEffect(()=>{ const io=new IntersectionObserver(async([e])=>{ if(e.isIntersecting && !src){ const { url }=await api.get(`/assets/${assetId}/signed`); setSrc(url); io.disconnect(); } }); if(ref.current) io.observe(ref.current); return ()=>io.disconnect(); },[assetId]);
  return <div ref={ref} style={{ width:w, height:h }}>{src && <img src={src} width={w} height={h} loading='lazy' />}</div>;
}

